import { useState } from "react";

function App() {
  const [message, setMessage] = useState("");
  const [response, setResponse] = useState("");
  const [messages, setMessages] = useState([]);
  const [isLoading, setIsLoading] = useState(false);

  const sendMessage = async () => {
    const trimmedMessage = message.trim();
    if (!trimmedMessage || isLoading) return;

    setMessages((prev) => [...prev, { role: "user", content: trimmedMessage }]);
    setMessage("");
    setIsLoading(true);

    const res = await fetch("http://localhost:8000/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ message: trimmedMessage }),
    });

    const data = await res.json();
    const aiReply = data.response || data.error || "No response received.";
    setResponse(aiReply);
    setMessages((prev) => [...prev, { role: "assistant", content: aiReply }]);
    setIsLoading(false);
  };

  return (
    <div className="h-screen bg-slate-950 text-slate-100">
      <div className="mx-auto flex h-full w-full max-w-5xl flex-col px-3 py-4 sm:px-5 sm:py-6">
        <header className="mb-4 rounded-2xl border border-slate-800/70 bg-slate-900/80 px-5 py-4 shadow-lg shadow-slate-950/30 backdrop-blur">
          <h1 className="bg-gradient-to-r from-blue-400 to-purple-500 bg-clip-text text-xl font-semibold text-transparent">
          "Mehdi's LLM AI"
          </h1>
          <p className="mt-1 text-sm text-slate-400">
            Ask anything and get instant AI-powered answers.
          </p>
        </header>

        <main className="flex-1 overflow-hidden rounded-2xl border border-slate-800/70 bg-slate-900/70 shadow-xl shadow-slate-950/40">
          <div className="h-full overflow-y-auto px-3 py-4 sm:px-5 sm:py-6">
            <div className="mx-auto flex w-full max-w-3xl flex-col gap-4">
              {messages.length === 0 && (
                <div className="rounded-2xl border border-slate-800 bg-slate-900/90 px-4 py-5 text-center text-sm text-slate-400">
                  Start a conversation with Ollama AI.
                </div>
              )}

              {messages.map((chatMessage, index) => (
                <div
                  key={`${chatMessage.role}-${index}`}
                  className={`animate-fadeIn ${
                    chatMessage.role === "user" ? "ml-auto" : "mr-auto"
                  } max-w-[85%] sm:max-w-[75%]`}
                >
                  <div
                    className={`rounded-2xl px-4 py-3 text-sm leading-relaxed shadow-md ${
                      chatMessage.role === "user"
                        ? "bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-blue-900/30"
                        : "bg-slate-800 text-slate-100 shadow-slate-900/50"
                    }`}
                  >
                    {chatMessage.content}
                  </div>
                </div>
              ))}

              {isLoading && (
                <div className="mr-auto max-w-[75%] animate-fadeIn">
                  <div className="inline-flex items-center gap-2 rounded-2xl bg-slate-800 px-4 py-3 text-sm text-slate-300 shadow-md shadow-slate-900/50">
                    <span className="h-2 w-2 animate-bounce rounded-full bg-slate-400 [animation-delay:-0.3s]" />
                    <span className="h-2 w-2 animate-bounce rounded-full bg-slate-400 [animation-delay:-0.15s]" />
                    <span className="h-2 w-2 animate-bounce rounded-full bg-slate-400" />
                    <span className="ml-1 text-slate-400">Thinking...</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </main>

        <footer className="sticky bottom-0 mt-4 rounded-2xl border border-slate-800/70 bg-slate-900/90 p-3 shadow-lg shadow-slate-950/40 backdrop-blur">
          <div className="mx-auto flex w-full max-w-3xl items-center gap-2 sm:gap-3">
            <input
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  sendMessage();
                }
              }}
              placeholder="Ask something..."
              className="w-full rounded-xl border border-slate-700 bg-slate-800/80 px-4 py-3 text-sm text-slate-100 placeholder:text-slate-500 outline-none transition focus:border-purple-500 focus:ring-2 focus:ring-purple-500/30"
            />

            <button
              onClick={sendMessage}
              disabled={!message.trim() || isLoading}
              className="inline-flex items-center justify-center rounded-xl bg-gradient-to-r from-blue-600 to-purple-600 px-4 py-3 text-sm font-medium text-white shadow-md shadow-purple-900/40 transition hover:brightness-110 focus:outline-none focus:ring-2 focus:ring-purple-500/40 disabled:cursor-not-allowed disabled:opacity-50"
            >
              <span className="hidden sm:inline">Send</span>
              <svg
                className="h-4 w-4 sm:ml-2"
                viewBox="0 0 24 24"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
              >
                <path
                  d="M5 12H19M19 12L13 6M19 12L13 18"
                  stroke="currentColor"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </button>
          </div>
        </footer>
      </div>

      <span className="sr-only">{response}</span>
    </div>
  );
}

export default App;
